const OPENROUTER_MODEL = "minimax/minimax-m2.7";
const OPENROUTER_URL = "https://openrouter.ai/api/v1/chat/completions";
const LLM_TIMEOUT_MS = 30_000;
const LOOP_LIMIT = 8;
const SOFT_TIMEOUT_MS = 50_000;
// Fallback regex to parse Llama-style tool calls from text when the model
// emits <function=tool_name{"arg":"val"}</function> instead of structured tool_calls.
const LLAMA_TOOL_CALL_RE = /<function=(\w+)([\s\S]*?)<\/function>/g;

type TimelineState = {
  config: TimelineConfig;
  configVersion: number;
  registry: AssetRegistry;
  projectId: string;
};

type LlmMessage = {
  role: "system" | "user" | "assistant" | "tool";
  content: string | null;
  tool_call_id?: string;
  tool_calls?: Array<{
    id: string;
    type: "function";
    function: {
      name: string;
      arguments: string;
    };
  }>;
};

interface AgentInvocationBody {
  session_id?: unknown;
  user_message?: unknown;
}

interface TimelineRow {
  config: TimelineConfig;
  config_version: number;
  asset_registry: AssetRegistry;
  project_id: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

function createToolTurn(
  role: Extract<AgentTurn["role"], "tool_call" | "tool_result">,
  toolName: string,
  content: string,
  toolArgs: Record<string, unknown>,
): AgentTurn {
  return {
    role,
    content,
    tool_name: toolName,
    tool_args: toolArgs,
    timestamp: new Date().toISOString(),
  };
}

function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "openrouter",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

function normalizeTimelineRow(row: Record<string, unknown>): TimelineRow {
  return {
    config: (row.config as TimelineConfig | null) ?? { output: { resolution: "1920x1080", fps: 30, file: "output.mp4" }, clips: [] },
    config_version: typeof row.config_version === "number" ? row.config_version : 1,
    asset_registry: (row.asset_registry as AssetRegistry | null) ?? { assets: {} },
    project_id: typeof row.project_id === "string" ? row.project_id : "",
  };
}

interface OpenRouterParams {
  model: string;
  messages: unknown[];
  tools?: unknown[];
  tool_choice?: string;
  temperature?: number;
  max_tokens?: number;
  top_p?: number;
}

interface OpenRouterResponse {
  choices: Array<{
    message: {
      role: string;
      content: string | null;
      tool_calls?: Array<{
        id: string;
        type: "function";
        function: { name: string; arguments: string };
      }>;
    };
  }>;
  usage?: { prompt_tokens: number; completion_tokens: number; total_tokens: number };
}

async function callOpenRouter(
  params: OpenRouterParams,
  logger: { info: (message: string, metadata?: Record<string, unknown>) => void },
): Promise<OpenRouterResponse> {
  const apiKey = Deno.env.get("OPENROUTER_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-timeline-agent] Missing OPENROUTER_API_KEY");
  }

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), LLM_TIMEOUT_MS);

  try {
    console.log(`[agent] OpenRouter request: model=${params.model} messages=${params.messages.length} tools=${params.tools?.length ?? 0}`);
    const response = await fetch(OPENROUTER_URL, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "Content-Type": "application/json",
        "HTTP-Referer": "https://reigh.app",
        "X-Title": "Reigh Timeline Agent",
      },
      body: JSON.stringify(params),
      signal: controller.signal,
    });

    if (!response.ok) {
      const text = await response.text().catch(() => "");
      console.error(`[agent] OpenRouter error ${response.status}: ${text.slice(0, 500)}`);
      throw new Error(`OpenRouter ${response.status}: ${text}`);
    }

    const data = await response.json() as OpenRouterResponse;
    const msg = data.choices?.[0]?.message;
    console.log(`[agent] OpenRouter response: tool_calls=${msg?.tool_calls?.length ?? 0} content_length=${msg?.content?.length ?? 0} usage=${JSON.stringify(data.usage ?? {})}`);
    logger.info("OpenRouter response received", {
      model: params.model,
      usage: data.usage,
    });
    return data;
  } finally {
    clearTimeout(timeout);
  }
}

function parseToolArgsSafely(rawArguments: unknown): {
  args: Record<string, unknown>;
  error: string | null;
} {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return { args: {}, error: null };
  }

  try {
    const parsed = JSON.parse(rawArguments);
    // Accept null, empty arrays, etc. as "no args" — only reject non-object primitives like strings/numbers
    if (parsed === null || parsed === undefined) {
      return { args: {}, error: null };
    }
    if (typeof parsed !== "object") {
      console.warn(`[agent] Tool args parsed to non-object: ${typeof parsed} — ${rawArguments.slice(0, 100)}`);
      return { args: {}, error: null };
    }
    return { args: isRecord(parsed) ? parsed : {}, error: null };
  } catch (error: unknown) {
    console.warn(`[agent] Failed to parse tool args: ${rawArguments.slice(0, 200)}`);
    return {
      args: {},
      error: `Invalid tool arguments JSON: ${toErrorMessage(error)}`,
    };
  }
}

function formatToolArgs(toolArgs: Record<string, unknown>): string {
  return JSON.stringify(toolArgs, null, 2);
}

function summarizeStoredToolTurn(turn: AgentTurn): string {
  const toolName = turn.tool_name ?? "tool";
  if (turn.role === "tool_call") {
    return `Tool call ${toolName}:\n${formatToolArgs(turn.tool_args ?? {})}`;
  }

  return `Tool result ${toolName}: ${turn.content}`;
}

