export type AgentSessionStatus =
  | "waiting_user"
  | "processing"
  | "continue"
  | "done"
  | "cancelled"
  | "error";

export type AgentTurn = {
  role: "user" | "assistant" | "tool_call" | "tool_result";
  content: string;
  tool_name?: string;
  tool_args?: Record<string, unknown>;
  timestamp: string;
};

export type AgentSession = {
  id: string;
  timeline_id: string;
  user_id: string;
  status: AgentSessionStatus;
  turns: AgentTurn[];
  model: string;
  summary: string | null;
  created_at: string;
  updated_at: string;
};

  const messages: LlmMessage[] = [{ role: "system", content: systemPrompt }];

  // Only send the most recent turns to avoid blowing up the context window.
  const recentTurns = turns.length > MAX_CONTEXT_TURNS
    ? turns.slice(-MAX_CONTEXT_TURNS)
    : turns;

  for (const turn of recentTurns) {
    if (turn.role === "user") {
      messages.push({ role: "user", content: turn.content });
      continue;
    }

    if (turn.role === "assistant") {
      messages.push({ role: "assistant", content: turn.content });
      continue;
    }

    messages.push({
      role: "assistant",
      content: summarizeStoredToolTurn(turn),
    });
  }

  return messages;
}

function extractAssistantText(message: { content?: unknown }): string {
  if (typeof message.content === "string") {
    return message.content.trim();
  }

  if (!Array.isArray(message.content)) {
    return "";
  }

  return message.content
    .flatMap((item) => {
      if (!isRecord(item)) {
        return [];
      }

      const text = item.text;
      return typeof text === "string" ? [text] : [];
    })
    .join("\n")
    .trim();
}

async function loadTimelineState(
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
  },
  timelineId: string,
): Promise<TimelineState> {
  const { data, error } = await supabaseAdmin
    .from("timelines")
    .select("config, config_version, asset_registry, project_id")
    .eq("id", timelineId)
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to load timeline: ${error.message}`);
  }

  if (!data || !isRecord(data)) {
    throw new Error("Timeline not found");
  }

  const normalized = normalizeTimelineRow(data);
  return {
    config: normalized.config,
    configVersion: normalized.config_version,
    registry: normalized.asset_registry,
    projectId: normalized.project_id,
  };
}

async function saveTimelineConfigVersioned(
  supabaseAdmin: {
    rpc: (
      fn: string,
      args: Record<string, unknown>,
    ) => { maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }> };
  },
  timelineId: string,
  expectedVersion: number,
  config: TimelineConfig,
): Promise<number | null> {
  const { data, error } = await supabaseAdmin
    .rpc("update_timeline_config_versioned", {
      p_timeline_id: timelineId,
      p_expected_version: expectedVersion,
      p_config: config,
    })
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to save timeline config: ${error.message}`);
  }

  const nextVersion = (data as { config_version?: unknown } | null)?.config_version;
  return typeof nextVersion === "number" ? nextVersion : null;
}

async function loadSessionStatus(
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
  },
  sessionId: string,
): Promise<AgentSessionStatus | null> {
  const { data, error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .select("status")
    .eq("id", sessionId)
    .maybeSingle();

  if (error || !data || !isRecord(data)) {
    return null;
  }

  return isSessionStatus(data.status) ? data.status : null;
}

async function persistSessionState(
  supabaseAdmin: {
    from: (table: string) => {
      update: (payload: Record<string, unknown>) => {
        eq: (column: string, value: string) => Promise<{ error: { message: string } | null }>;
      };
    };
  },
  options: {
    sessionId: string;
    status: AgentSessionStatus;
    turns: AgentTurn[];
    summary: string | null;
  },
): Promise<void> {
  const { error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .update({
      status: options.status,
      turns: options.turns,
      summary: options.summary,
      updated_at: new Date().toISOString(),
    })
    .eq("id", options.sessionId);

  if (error) {
    throw new Error(`Failed to persist session state: ${error.message}`);
  }
}

