async function callOpenRouter(
  params: OpenRouterParams,
  logger: { info: (message: string, metadata?: Record<string, unknown>) => void },
): Promise<OpenRouterResponse> {
  const apiKey = Deno.env.get("OPENROUTER_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-timeline-agent] Missing OPENROUTER_API_KEY");
  }

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), LLM_TIMEOUT_MS);

  try {
    console.log(`[agent] OpenRouter request: model=${params.model} messages=${params.messages.length} tools=${params.tools?.length ?? 0}`);
    const response = await fetch(OPENROUTER_URL, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "Content-Type": "application/json",
        "HTTP-Referer": "https://reigh.app",
        "X-Title": "Reigh Timeline Agent",
      },
      body: JSON.stringify(params),
      signal: controller.signal,
    });

    if (!response.ok) {
      const text = await response.text().catch(() => "");
      console.error(`[agent] OpenRouter error ${response.status}: ${text.slice(0, 500)}`);
      throw new Error(`OpenRouter ${response.status}: ${text}`);
    }

    const data = await response.json() as OpenRouterResponse;
    const msg = data.choices?.[0]?.message;
    console.log(`[agent] OpenRouter response: tool_calls=${msg?.tool_calls?.length ?? 0} content_length=${msg?.content?.length ?? 0} usage=${JSON.stringify(data.usage ?? {})}`);
    logger.info("OpenRouter response received", {
      model: params.model,
      usage: data.usage,
    });
    return data;
  } finally {
    clearTimeout(timeout);
  }
}

function parseToolArgsSafely(rawArguments: unknown): {
  args: Record<string, unknown>;
  error: string | null;
} {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return { args: {}, error: null };
  }

  try {
    const parsed = JSON.parse(rawArguments);
    // Accept null, empty arrays, etc. as "no args" — only reject non-object primitives like strings/numbers
    if (parsed === null || parsed === undefined) {
      return { args: {}, error: null };
    }
    if (typeof parsed !== "object") {
      console.warn(`[agent] Tool args parsed to non-object: ${typeof parsed} — ${rawArguments.slice(0, 100)}`);
      return { args: {}, error: null };
    }
    return { args: isRecord(parsed) ? parsed : {}, error: null };
  } catch (error: unknown) {
    console.warn(`[agent] Failed to parse tool args: ${rawArguments.slice(0, 200)}`);
    return {
      args: {},
      error: `Invalid tool arguments JSON: ${toErrorMessage(error)}`,
    };
  }
}

