async function executeTimelineTool(
  toolName: keyof typeof timelineTools,
  toolArgs: Record<string, unknown>,
  state: TimelineState,
  timelineId: string,
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
    rpc: (
      fn: string,
      args: Record<string, unknown>,
    ) => { maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }> };
  },
): Promise<TimelineToolResult> {
  const runTool = () => timelineTools[toolName](state.config, state.registry, toolArgs);
  let result = runTool();

  if (!result.config) {
    return result;
  }

  let nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion !== null) {
    state.config = result.config;
    state.configVersion = nextVersion;
    return result;
  }

  const refreshedState = await loadTimelineState(supabaseAdmin, timelineId);
  state.config = refreshedState.config;
  state.configVersion = refreshedState.configVersion;
  state.registry = refreshedState.registry;
  state.projectId = refreshedState.projectId;

  result = runTool();
  if (!result.config) {
    return {
      result: `${result.result} (retried after reload.)`,
    };
  }

  nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion === null) {
    return {
      result: `Version conflict prevented applying ${toolName}. Please retry after the latest timeline reload.`,
    };
  }

  state.config = result.config;
  state.configVersion = nextVersion;
  return {
    ...result,
    result: `${result.result} (retried after reload.)`,
  };
}

async function invokeLlmWithRetry(
  params: OpenRouterParams,
  logger: {
    error: (message: string, metadata?: Record<string, unknown>) => void;
    info: (message: string, metadata?: Record<string, unknown>) => void;
  },
): Promise<OpenRouterResponse> {
  try {
    return await callOpenRouter(params, logger);
  } catch (firstError: unknown) {
    logger.error("OpenRouter call failed on first attempt", {
      error: toErrorMessage(firstError),
    });

    try {
      return await callOpenRouter(params, logger);
    } catch (secondError: unknown) {
      logger.error("OpenRouter call failed on retry", {
        error: toErrorMessage(secondError),
      });
      throw secondError;
    }
  }
}

