              model: OPENROUTER_MODEL,
              messages: messages as unknown[],
              tools: TIMELINE_AGENT_TOOLS as unknown[],
              tool_choice: "auto",
              temperature: 0.2,
              max_tokens: 4096,
              top_p: 1,
            },
            logger,
          );
        } catch (llmError: unknown) {
          const text = `The timeline agent hit an AI service error: ${toErrorMessage(llmError)}. Please retry in a moment.`;
          turns.push(createTurn("assistant", text));
          messages.push({ role: "assistant", content: text });
          status = "waiting_user";
          break;
        }

        const responseMessage = completion.choices[0]?.message;
        if (!responseMessage) {
          turns.push(createTurn("assistant", "I couldn't produce a response."));
          status = "waiting_user";
          break;
        }

        const assistantText = extractAssistantText(responseMessage);
        const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
          ? ((responseMessage as { tool_calls: unknown[] }).tool_calls as unknown[])
          : [];
        const toolCalls = rawToolCalls.flatMap((toolCall) => {
          if (!isRecord(toolCall)) {
            return [];
          }

          const fn = isRecord(toolCall.function) ? toolCall.function : undefined;
          if (!fn || typeof fn.name !== "string") {
            return [];
          }

          return [{
            id: typeof toolCall.id === "string" ? toolCall.id : crypto.randomUUID(),
            type: "function" as const,
            function: {
              name: fn.name,
              arguments: typeof fn.arguments === "string" ? fn.arguments : "{}",
            },
          }];
        });

        // Fallback: if the model emitted Llama-style <function=name{args}</function>
        // in the text content instead of structured tool_calls, parse them out.
        if (toolCalls.length === 0 && assistantText) {
          LLAMA_TOOL_CALL_RE.lastIndex = 0;
          let match: RegExpExecArray | null;
          while ((match = LLAMA_TOOL_CALL_RE.exec(assistantText)) !== null) {
            const name = match[1];
            const argsStr = match[2].trim();
            try {
              const parsedArgs = argsStr ? JSON.parse(argsStr) : {};
              toolCalls.push({
                id: crypto.randomUUID(),
                type: "function" as const,
                function: { name, arguments: JSON.stringify(parsedArgs) },
              });
            } catch {
              logger.warn(`Failed to parse Llama-style tool call args for ${name}: ${argsStr}`);
            }
          }

          if (toolCalls.length > 0) {
            logger.info(`Recovered ${toolCalls.length} tool call(s) from Llama-style text format`);
          }
        }

        if (toolCalls.length === 0) {
          const text = assistantText || "I need a bit more direction before changing the timeline.";
          turns.push(createTurn("assistant", text));
          messages.push({ role: "assistant", content: text });
          status = "waiting_user";
          break;
        }

        messages.push({
          role: "assistant",
          content: assistantText || null,
          tool_calls: toolCalls,
        });

        for (const toolCall of toolCalls) {
          if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
            status = "continue";
            break loop;
          }

          const currentStatusBeforeTool = await loadSessionStatus(supabaseAdmin, session.id);
          if (currentStatusBeforeTool === "cancelled") {
            status = "cancelled";
            break loop;
          }

          const toolName = toolCall.function.name;
          const { args: toolArgs, error: toolArgsError } = parseToolArgsSafely(toolCall.function.arguments);
          turns.push(createToolTurn(
            "tool_call",
            toolName,
            `Called ${toolName}.`,
            toolArgs,
          ));

          let toolResult:
            | TimelineToolResult
            | Awaited<ReturnType<(typeof sessionTools)[keyof typeof sessionTools]>>;

          if (toolArgsError) {
            toolResult = {
              result: toolArgsError,
            };
          } else if (toolName in timelineTools) {
            toolResult = await executeTimelineTool(
              toolName as keyof typeof timelineTools,
              toolArgs,
              timelineState,
              session.timeline_id,
              supabaseAdmin,
            );
          } else if (toolName in sessionTools) {
            const tool = sessionTools[toolName as keyof typeof sessionTools];
            if (toolName === "message_user") {
              toolResult = typeof toolArgs.text === "string"
                ? tool(toolArgs.text) as ReturnType<typeof sessionTools.message_user>
                : { result: "message_user requires a text string." };
            } else if (toolName === "done") {
              toolResult = typeof toolArgs.summary === "string"
                ? tool(toolArgs.summary) as ReturnType<typeof sessionTools.done>
                : { result: "done requires a summary string." };
            } else {
              toolResult = await tool(toolArgs as never);
            }
          } else {
            toolResult = { result: `Unknown tool ${toolName}.` };
          }

          turns.push(createToolTurn("tool_result", toolName, toolResult.result, toolArgs));
          messages.push({
            role: "tool",
            tool_call_id: toolCall.id,
            content: toolResult.result,
          });

          if (toolName === "message_user" || toolName === "done") {
            turns.push(createTurn("assistant", toolResult.result));
          }

          if ("stopLoop" in toolResult && toolResult.stopLoop) {
            status = toolResult.nextStatus ?? "waiting_user";
            if (toolName === "done") {
              summary = toolResult.result;
            }
            break loop;
          }
        }
      }

      if (status === "processing") {
        status = "continue";
      }

      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status,
        turns,
        summary,
      });

      logger.info("Agent loop completed", {
        session_id: session.id,
        status,
        turns_added: turns.length - turnsBeforeInvocation,
        tool_count: TIMELINE_AGENT_TOOLS.length,
      });

      return jsonResponse({
        session_id: session.id,
        status,
        turns_added: turns.length - turnsBeforeInvocation,
        tool_count: TIMELINE_AGENT_TOOLS.length,
        model: session.model,
      });
    } catch (error: unknown) {
      const errorDetail = toErrorMessage(error);
      console.error(`[agent] FATAL: ${errorDetail}`);
      logger.error("Agent loop failed", {
        session_id: session.id,
        error: errorDetail,
      });

      // Write the error into turns so it's visible from DB inspection
      turns.push(createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`));

      try {
        await persistSessionState(supabaseAdmin, {
          sessionId: session.id,
          status: "error",
          turns,
          summary,
        });
      } catch (persistError: unknown) {
        logger.error("Failed to persist error state", {
          session_id: session.id,
          error: toErrorMessage(persistError),
        });

export function buildTimelineAgentSystemPrompt(
  options: {
    projectId: string;
    timelineSummary: string;
  },
): string {
  return [
    "You are a turn-based video timeline editing agent.",
    "You must use tools to inspect and modify the timeline instead of pretending edits happened.",
    "When you need to answer the user conversationally and wait for input, call message_user.",
    "When the task is complete, call done with a concise summary.",
    "Use create_generation_task only for image_generation tasks.",
    `If you call create_generation_task, use project_id=${options.projectId}.`,
    "If a tool returns an error, read it carefully and correct the next tool call.",
    "Do not mention unavailable transcript-based issue detection.",
    "",
    "Current timeline view:",
    options.timelineSummary,
  ].join("\n");
}

import { toErrorMessage } from "../../_shared/errorMessage.ts";
import { MAX_CONTEXT_TURNS } from "../config.ts";
import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
  LlmMessage,
  TimelineRow,
} from "../types.ts";
import type { AssetRegistry, TimelineConfig } from "../../../../src/tools/video-editor/types/index.ts";

export function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

export function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

export function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

export function createToolTurn(
  role: Extract<AgentTurn["role"], "tool_call" | "tool_result">,
  toolName: string,
  content: string,
  toolArgs: Record<string, unknown>,
): AgentTurn {
  return {
    role,
    content,
    tool_name: toolName,
    tool_args: toolArgs,
    timestamp: new Date().toISOString(),
  };
}

export function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "openrouter",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

export function normalizeTimelineRow(row: Record<string, unknown>): TimelineRow {
  return {
    config: (row.config as TimelineConfig | null)
      ?? { output: { resolution: "1920x1080", fps: 30, file: "output.mp4" }, clips: [] },
    config_version: typeof row.config_version === "number" ? row.config_version : 1,
    asset_registry: (row.asset_registry as AssetRegistry | null) ?? { assets: {} },
    project_id: typeof row.project_id === "string" ? row.project_id : "",
  };
}

export function parseToolArgsSafely(rawArguments: unknown): {
  args: Record<string, unknown>;
  error: string | null;
} {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return { args: {}, error: null };
  }

  try {
    const parsed = JSON.parse(rawArguments);
    // Accept null, empty arrays, etc. as "no args" — only reject non-object primitives like strings/numbers
    if (parsed === null || parsed === undefined) {
      return { args: {}, error: null };
    }
    if (typeof parsed !== "object") {
      console.warn(`[agent] Tool args parsed to non-object: ${typeof parsed} — ${rawArguments.slice(0, 100)}`);
      return { args: {}, error: null };
    }
    return { args: isRecord(parsed) ? parsed : {}, error: null };
  } catch (error: unknown) {
    console.warn(`[agent] Failed to parse tool args: ${rawArguments.slice(0, 200)}`);
    return {
      args: {},
      error: `Invalid tool arguments JSON: ${toErrorMessage(error)}`,
    };
  }
}

export function formatToolArgs(toolArgs: Record<string, unknown>): string {
  return JSON.stringify(toolArgs, null, 2);
}

export function summarizeStoredToolTurn(turn: AgentTurn): string {
  const toolName = turn.tool_name ?? "tool";
  if (turn.role === "tool_call") {
    return `Tool call ${toolName}:\n${formatToolArgs(turn.tool_args ?? {})}`;
  }

  return `Tool result ${toolName}: ${turn.content}`;
}

export function buildInitialMessages(
  systemPrompt: string,
  turns: AgentTurn[],
): LlmMessage[] {
  const messages: LlmMessage[] = [{ role: "system", content: systemPrompt }];

  // Only send the most recent turns to avoid blowing up the context window.
  const recentTurns = turns.length > MAX_CONTEXT_TURNS
    ? turns.slice(-MAX_CONTEXT_TURNS)
    : turns;

  for (const turn of recentTurns) {
    if (turn.role === "user") {
      messages.push({ role: "user", content: turn.content });
      continue;
    }

    if (turn.role === "assistant") {
      messages.push({ role: "assistant", content: turn.content });
      continue;
    }

    messages.push({
      role: "assistant",
      content: summarizeStoredToolTurn(turn),
    });
  }

  return messages;
}

export function extractAssistantText(message: { content?: unknown }): string {
  if (typeof message.content === "string") {
    return message.content.trim();
  }

  if (!Array.isArray(message.content)) {
    return "";
  }

  return message.content
    .flatMap((item) => {
      if (!isRecord(item)) {
        return [];
      }

      const text = item.text;
      return typeof text === "string" ? [text] : [];
    })
    .join("\n")
    .trim();
}

import { loadTimelineState, saveTimelineConfigVersioned } from "../db.ts";
import type {
  SupabaseAdmin,
  TimelineState,
  ToolContext,
  ToolHandler,
  ToolResult,
} from "../types.ts";
import { handlers as generationHandlers } from "./generation.ts";
import { handlers as sessionHandlers } from "./session.ts";
import { handlers as timelineHandlers } from "./timeline.ts";

export const TOOL_REGISTRY: Record<string, ToolHandler> = {
  ...timelineHandlers,
  ...sessionHandlers,
  ...generationHandlers,
};

const TIMELINE_TOOL_NAMES = new Set(Object.keys(timelineHandlers));

function buildContext(ctx: ToolContext, state: TimelineState): ToolContext {
  return {
    ...ctx,
    config: state.config,
    registry: state.registry,
    projectId: state.projectId,
  };
}

export async function executeTool(
  name: string,
  args: Record<string, unknown>,
  ctx: ToolContext,
  state: TimelineState,
  timelineId: string,
  supabaseAdmin: SupabaseAdmin,
): Promise<ToolResult> {
  const handler = TOOL_REGISTRY[name];
  if (!handler) {
    return { result: `Unknown tool ${name}.` };
  }

  if (!TIMELINE_TOOL_NAMES.has(name)) {
    return await handler(args, buildContext(ctx, state));
  }

  const runTool = () => handler(args, buildContext(ctx, state));
  let result = await runTool();

  if (!result.config) {
    return result;
  }

  let nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion !== null) {
    state.config = result.config;
    state.configVersion = nextVersion;
    return result;
  }

  const refreshedState = await loadTimelineState(supabaseAdmin, timelineId);
  state.config = refreshedState.config;
  state.configVersion = refreshedState.configVersion;
  state.registry = refreshedState.registry;
  state.projectId = refreshedState.projectId;

  result = await runTool();
  if (!result.config) {
    return {
      result: `${result.result} (retried after reload.)`,
    };
  }

  nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion === null) {
    return {
      result: `Version conflict prevented applying ${name}. Please retry after the latest timeline reload.`,
    };
  }

  state.config = result.config;
  state.configVersion = nextVersion;
  return {
    ...result,
    result: `${result.result} (retried after reload.)`,
  };
}

import type { TimelineConfig } from "../../../src/tools/video-editor/types/index.ts";
import { isRecord, isSessionStatus, normalizeTimelineRow } from "./llm/messages.ts";
import type {
  AgentSessionStatus,
  AgentTurn,
  SupabaseAdmin,
  TimelineState,
} from "./types.ts";

export async function loadTimelineState(
  supabaseAdmin: SupabaseAdmin,
  timelineId: string,
): Promise<TimelineState> {
  const { data, error } = await supabaseAdmin
    .from("timelines")
    .select("config, config_version, asset_registry, project_id")
    .eq("id", timelineId)
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to load timeline: ${error.message}`);
  }

  if (!data || !isRecord(data)) {
    throw new Error("Timeline not found");
  }

  const normalized = normalizeTimelineRow(data);
  return {
    config: normalized.config,
    configVersion: normalized.config_version,
    registry: normalized.asset_registry,
    projectId: normalized.project_id,
  };
}

export async function saveTimelineConfigVersioned(
  supabaseAdmin: SupabaseAdmin,
  timelineId: string,
  expectedVersion: number,
  config: TimelineConfig,
): Promise<number | null> {
  const { data, error } = await supabaseAdmin
    .rpc("update_timeline_config_versioned", {
      p_timeline_id: timelineId,
      p_expected_version: expectedVersion,
      p_config: config,
    })
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to save timeline config: ${error.message}`);
  }

  const nextVersion = (data as { config_version?: unknown } | null)?.config_version;
  return typeof nextVersion === "number" ? nextVersion : null;
}

export async function loadSessionStatus(
  supabaseAdmin: SupabaseAdmin,
  sessionId: string,
): Promise<AgentSessionStatus | null> {
  const { data, error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .select("status")
    .eq("id", sessionId)
    .maybeSingle();

  if (error || !data || !isRecord(data)) {
    return null;
  }

  return isSessionStatus(data.status) ? data.status : null;
}

export async function persistSessionState(
  supabaseAdmin: SupabaseAdmin,
  options: {
    sessionId: string;
    status: AgentSessionStatus;
    turns: AgentTurn[];
    summary: string | null;
  },
): Promise<void> {
  const { error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .update({
      status: options.status,
      turns: options.turns,
      summary: options.summary,
      updated_at: new Date().toISOString(),
    })
    .eq("id", options.sessionId);

  if (error) {
    throw new Error(`Failed to persist session state: ${error.message}`);
  }
