import type { EdgeRuntime } from "../_shared/edgeRequest.ts";
import { toErrorMessage } from "../_shared/errorMessage.ts";
import {
  LOOP_LIMIT,
  OPENROUTER_MODEL,
  SOFT_TIMEOUT_MS,
} from "./config.ts";
import { loadSessionStatus, loadTimelineState, persistSessionState } from "./db.ts";
import { invokeLlmWithRetry } from "./llm/client.ts";
import {
  buildInitialMessages,
  createToolTurn,
  createTurn,
  extractAssistantText,
  isRecord,
  parseToolArgsSafely,
} from "./llm/messages.ts";
import { buildTimelineAgentSystemPrompt } from "./prompts.ts";
import { TIMELINE_AGENT_TOOLS } from "./tools.ts";
import { executeTool } from "./tools/registry.ts";
import { viewTimeline } from "./tools/timeline.ts";
import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
  SupabaseAdmin,
} from "./types.ts";

type LoopLogger = Pick<EdgeRuntime["logger"], "error" | "info">;

export interface RunAgentLoopOptions {
  session: AgentSession;
  userMessage?: string;
  supabaseAdmin: SupabaseAdmin;
  logger: LoopLogger;
}

export interface RunAgentLoopResult {
  status: AgentSessionStatus;
  turns: AgentTurn[];
  summary: string | null;
}

export async function runAgentLoop(
  options: RunAgentLoopOptions,
): Promise<RunAgentLoopResult> {
  const { session, userMessage, supabaseAdmin, logger } = options;

  // Guard against duplicate user messages (client may retry or double-fire)
  const lastTurn = session.turns[session.turns.length - 1];
  const isDuplicate = userMessage
    && lastTurn?.role === "user"
    && lastTurn.content === userMessage;
  const turns = (userMessage && !isDuplicate)
    ? [...session.turns, createTurn("user", userMessage)]
    : [...session.turns];
  let status: AgentSessionStatus = "processing";
  let summary = session.summary;
  const turnsBeforeInvocation = session.turns.length;

  try {
    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
    const timelineSummary = viewTimeline(timelineState.config, timelineState.registry).result;
    const systemPrompt = buildTimelineAgentSystemPrompt({
      projectId: timelineState.projectId,
      timelineSummary,
    });
    const messages = buildInitialMessages(systemPrompt, turns);
    const startedAt = Date.now();

    loop: for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
      if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
        status = "continue";
        break;
      }

      const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
      if (currentStatus === "cancelled") {
        status = "cancelled";
        break;
      }

      let completion;
      try {
        completion = await invokeLlmWithRetry(
          {
            model: OPENROUTER_MODEL,
            messages: messages as unknown[],
            tools: TIMELINE_AGENT_TOOLS as unknown[],
            tool_choice: "auto",
            temperature: 0.2,
            max_tokens: 4096,
            top_p: 1,
          },
          logger,
        );
      } catch (llmError: unknown) {
        const text = `The timeline agent hit an AI service error: ${toErrorMessage(llmError)}. Please retry in a moment.`;
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      const responseMessage = completion.choices[0]?.message;
      if (!responseMessage) {
        turns.push(createTurn("assistant", "I couldn't produce a response."));
        status = "waiting_user";
        break;
      }

      const assistantText = extractAssistantText(responseMessage);
      const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
        ? ((responseMessage as { tool_calls: unknown[] }).tool_calls as unknown[])
        : [];
      const toolCalls = rawToolCalls.flatMap((toolCall) => {
        if (!isRecord(toolCall)) {
          return [];
        }

        const fn = isRecord(toolCall.function) ? toolCall.function : undefined;
        if (!fn || typeof fn.name !== "string") {
          return [];
        }

        return [{
          id: typeof toolCall.id === "string" ? toolCall.id : crypto.randomUUID(),
          type: "function" as const,
          function: {
            name: fn.name,
            arguments: typeof fn.arguments === "string" ? fn.arguments : "{}",
          },
        }];
      });

      if (toolCalls.length === 0) {
        const text = assistantText || "I need a bit more direction before changing the timeline.";
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      messages.push({
        role: "assistant",
        content: assistantText || null,
        tool_calls: toolCalls,
      });

      for (const toolCall of toolCalls) {
        if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
          status = "continue";
          break loop;
        }

        const currentStatusBeforeTool = await loadSessionStatus(supabaseAdmin, session.id);
        if (currentStatusBeforeTool === "cancelled") {
          status = "cancelled";
          break loop;
        }

        const toolName = toolCall.function.name;
        const { args: toolArgs, error: toolArgsError } = parseToolArgsSafely(toolCall.function.arguments);
        turns.push(createToolTurn(
          "tool_call",
          toolName,
          `Called ${toolName}.`,
          toolArgs,
        ));

        const toolResult = toolArgsError
          ? { result: toolArgsError }
          : await executeTool(
            toolName,
            toolArgs,
            {
              config: timelineState.config,
              registry: timelineState.registry,
              projectId: timelineState.projectId,
            },
            timelineState,
            session.timeline_id,
            supabaseAdmin,
          );

        turns.push(createToolTurn("tool_result", toolName, toolResult.result, toolArgs));
        messages.push({
          role: "tool",
          tool_call_id: toolCall.id,
          content: toolResult.result,
        });

        if ("stopLoop" in toolResult && toolResult.stopLoop) {
          status = toolResult.nextStatus ?? "waiting_user";
          if (toolName === "done") {
            summary = toolResult.result;
          }
          break loop;
        }
      }
    }

    if (status === "processing") {
      status = "continue";
    }

    logger.info("Agent loop completed", {
      session_id: session.id,
      status,
      turns_added: turns.length - turnsBeforeInvocation,
      tool_count: TIMELINE_AGENT_TOOLS.length,
    });

    return {
      status,
      turns,
      summary,
    };
  } catch (error: unknown) {
    const errorDetail = toErrorMessage(error);
    console.error(`[agent] FATAL: ${errorDetail}`);
    logger.error("Agent loop failed", {
      session_id: session.id,
      error: errorDetail,
    });

    // Write the error into turns so it's visible from DB inspection
    turns.push(createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`));

    try {
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status: "error",
        turns,
        summary,
      });
    } catch (persistError: unknown) {
      logger.error("Failed to persist error state", {
        session_id: session.id,
        error: toErrorMessage(persistError),
      });
    }

    throw error;
  }
}

